import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class OvernemenBijAchterstal extends AbstractRekenCommand {

    @Override
    protected boolean execute(RekenContext context) {
        RekenContext preBerekeningContext = context.getUnchecked(RekenTools.bepaalVorigeBerekeningType(context));
        if (!preBerekeningContext.isEmpty()) {
            overnemenBedrijfsvoorheffing(context, preBerekeningContext);
            overnemenOudeAchterstalBv(context, preBerekeningContext);
            sommeerOvergenomenKeys(context);
        }

        return CONTINUE_PROCESSING;
    }

    private static final RekenBvKey[] OVERNEMENEN_BIJ_ACHTERSTAL_KEYS =
            {BEDRIJFSVOORHEFFING_EXCEPTIONEEL_KEY, BEDRIJFSVOORHEFFING_VAKANTIEGELD_KEY, BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_ZIEKTE_KEY,
                    BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_PREMIE_KEY, BEDRIJFSVOORHEFFING_UITTREDING_MANDATARIS_KEY,
                    BEDRIJFSVOORHEFFING_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY, BEDRIJFSVOORHEFFING_BESTAANS_VERZEKERING_KEY,
                    BEDRIJFSVOORHEFFING_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY,
                    BEDRIJFSVOORHEFFING_VRIJWILLIGE_BRANDWEER_KEY, BEDRIJFSVOORHEFFING_TIJDELIJKE_WERKLOOSHEID_KEY, BEDRIJFSVOORHEFFING_OPZEG_VERGOEDING_KEY,
                    BEDRIJFSVOORHEFFING_FIETS_VERGOEDING_KEY, BEDRIJFSVOORHEFFING_TOEVALLIGE_VERGOEDINGEN_KEY, BEDRIJFSVOORHEFFING_WINST_PREMIE_KEY};

    private static final RekenBvKey[] OVERNEMENEN_OUDE_ACHTERSTAL_KEYS =
            {BEDRIJFSVOORHEFFING_ACHTERSTAL_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_ARBEIDS_ONGESCHIKTHEID_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_PREMIE_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_UITTREDING_MANDATARIS_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_ZIEKTE_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_VERVANGINGS_INKOMEN_INSTAP_STAGE_KEY,
                    RekenBvKey.BEDRIJFSVOORHEFFING_ACHTERSTAL_BESTAANS_VERZEKERING_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_TIJDELIJKE_WERKLOOSHEID_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_VRIJWILLIGE_BRANDWEER_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_OPZEG_VERGOEDING_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_FIETS_VERGOEDING_KEY,
                    BEDRIJFSVOORHEFFING_ACHTERSTAL_TOEVALLIGE_VERGOEDINGEN_KEY, BEDRIJFSVOORHEFFING_ACHTERSTAL_WINST_PREMIE_KEY};

    public static final Set<MoneyKey> OVERNEMENEN_KEYS;

    static {
        Set<MoneyKey> temp = new HashSet<>();
        Collections.addAll(temp, OVERNEMENEN_BIJ_ACHTERSTAL_KEYS);
        temp.add(RekenBvKey.BEDRIJFSVOORHEFFING_GEWONE_BEZOLDIGING_KEY);
        temp.add(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY);
        temp.add(RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY);
        Collections.addAll(temp, OVERNEMENEN_OUDE_ACHTERSTAL_KEYS);
        for (RekenBvKey key : OVERNEMENEN_OUDE_ACHTERSTAL_KEYS) {
            temp.add(key.getOud());
        }
        OVERNEMENEN_KEYS = Collections.unmodifiableSet(temp);
    }

    private void overnemenBedrijfsvoorheffing(RekenContext mainContext, RekenContext preBerekeningContext) {
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        LoonElementManager loonElementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        LoonElementManager prevLoonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext preOpdrachtContext = preBerekeningContext.getOpdrachtContext(opdracht);
            if (preOpdrachtContext != null) {
                overnemenenBedrijfsvoorheffingOpdracht(opdracht, rekenTijd.rekenPeriode, loonElementManager, prevLoonElementManager);
                overnemenBedrijfsvoorheffingGewoonOpdracht(opdracht, rekenTijd.rekenPeriode, loonElementManager, prevLoonElementManager);
            }
        }
    }

    private void sommeerOvergenomenKeys(RekenContext mainContext) {
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        LoonElementManager loonElementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (Opdracht opdracht : persoon.getOpdrachten()) {
            RekenContext opdrachtContext = mainContext.getOpdrachtContext(opdracht);
            Collection<LoonElement> opdrachtsElementen = loonElementManager.getOpdrachtsElementen(opdracht);
            for (MoneyKey opdrachtBedragKey : OVERNEMENEN_KEYS) {
                opdrachtContext.put(opdrachtBedragKey, RekenTools.getSomProperty(opdrachtBedragKey, opdrachtsElementen));
            }

            for (LoonElement element : opdrachtsElementen) {
                LnedefRegBv regime = element.getRegimeBv();
                ContextKey key = new BelastbaarKey(regime);
                Money belastbaar = element.getPropertyMoney(BELASTBAAR_KEY);
                opdrachtContext.addToProperty(key, belastbaar);
            }
        }
    }

    private void overnemenOudeAchterstalBv(RekenContext mainContext, RekenContext preBerekeningContext) {
        for (RekenBvKey achterstalBvKey : OVERNEMENEN_OUDE_ACHTERSTAL_KEYS) {
            overnemenOudeAchterstalBv(mainContext, preBerekeningContext, achterstalBvKey);
        }
    }

    private void overnemenOudeAchterstalBv(RekenContext mainContext, RekenContext preBerekeningContext, RekenBvKey achterstalBvKey) {
        ListMultimap<OpdrachtAardKodeExtensieRefJaarKey, MoneyDatum> oudAchterstalMap = ArrayListMultimap.create();

        LoonElementManager prevLoonElementManager = preBerekeningContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (LoonElement element : prevLoonElementManager.getPersoonsElementen()) {
            OpdrachtAardKodeExtensieRefJaarKey oudKey =
                    new OpdrachtAardKodeExtensieRefJaarKey(element.getOpdracht(), element.getAardKodeExtensie(), element.getReferentieJaar(),
                            element.getRegimeBv());
            Money achterstalBv = element.getPropertyMoney(achterstalBvKey);
            if (achterstalBv.signum() != 0) {
                oudAchterstalMap.put(oudKey, new MoneyDatum(achterstalBv, element.getOpper().getActualTo()));
            }
        }

        ListMultimap<OpdrachtAardKodeExtensieRefJaarKey, LoonElement> oudAchterstalKeyToLoonElementen = ArrayListMultimap.create();
        LoonElementManager loonElementManager = mainContext.getUnchecked(LOONELEMENT_MANAGER_KEY);
        for (LoonElement element : loonElementManager.getPersoonsElementen()) {
            OpdrachtAardKodeExtensieRefJaarKey oudKey =
                    new OpdrachtAardKodeExtensieRefJaarKey(element.getOpdracht(), element.getAardKodeExtensie(), element.getReferentieJaar(),
                            element.getRegimeBv());
            oudAchterstalKeyToLoonElementen.put(oudKey, element);
        }

        for (OpdrachtAardKodeExtensieRefJaarKey oudKey : oudAchterstalMap.keySet()) {
            List<MoneyDatum> oudAchterstalBvs = oudAchterstalMap.get(oudKey);
            List<LoonElement> loonElementen = oudAchterstalKeyToLoonElementen.get(oudKey);
            for (MoneyDatum oudAchterstalBv : oudAchterstalBvs) {
                boolean found = false;
                for (LoonElement element : loonElementen) {
                    Opper opper = element.getOpper();
                    LocalDateInterval opperInterval = opper.getActualInterval();
                    if (opperInterval.contains(oudAchterstalBv.getDatum())) {
                        element.addToProperty(achterstalBvKey.getOud(), oudAchterstalBv.getMoney());
                        found = true;
                        break;
                    }
                }
                if (!found) {
                    Opper opper = RekenTools.findOpper(oudKey.getOpdracht(), oudAchterstalBv.getDatum());
                    LoonElement bestaand = loonElementManager.getLoonElement(oudKey.getAardKodeExtensie(), opper, oudKey.getReferentieJaar());
                    if (bestaand != null) {
                        bestaand.addToProperty(achterstalBvKey.getOud(), oudAchterstalBv.getMoney());
                    } else {
                        LoonElement element = new LoonElement(oudKey.getAardKodeExtensie());
                        element.setReferentieJaar(oudKey.getReferentieJaar());
                        element.putProperty(AFWIJKEND_REGIME_KEY, oudKey.getRegimeBv());
                        element.putProperty(achterstalBvKey.getOud(), oudAchterstalBv.getMoney());

                        if (opper == null) {
                            opper = RekenTools.getOpperLaatsteGegevens(oudKey.getOpdracht());
                        }
                        loonElementen.add(element);
                        oudAchterstalKeyToLoonElementen.put(oudKey, element);
                        loonElementManager.addLoonElement(element, opper);
                    }
                }
            }
        }
    }

    private static class MoneyDatum {

        private Money money;
        private LocalDate datum;

        public MoneyDatum(Money money, LocalDate datum) {
            this.money = money;
            this.datum = datum;
        }

        public Money getMoney() {
            return money;
        }

        public LocalDate getDatum() {
            return datum;
        }

    }

    private void overnemenenBedrijfsvoorheffingOpdracht(
            Opdracht opdracht, LocalDateInterval rekenPeriode, LoonElementManager manager,
            LoonElementManager prevManager) {
        Collection<LoonElement> prevLoonElementen = prevManager.getOpdrachtsElementen(opdracht);

        for (MoneyKey bvKey : OVERNEMENEN_BIJ_ACHTERSTAL_KEYS) {
            LoonElementChecker checkRegime = new CheckRegime(rekenPeriode.getEnd(), bvKey);
            Collection<LoonElement> prevRegimeElementen = RekenTools.filter(prevLoonElementen, checkRegime);
            RekenTools.overnemenVanVorigeBerekening(bvKey, manager, prevRegimeElementen);
        }
    }

    private static final RekenBvSubKey[] TE_VERDELEN_BEDRIJFSVOORHEFFING_SUB =
            {RekenBvSubKey.BV_GEWONE_BEZOLDIGING_NORM_KEY, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_PENS_KEY, RekenBvSubKey.BV_GEWONE_BEZOLDIGING_ZIV_KEY,
                    RekenBvSubKey.BV_VEREFFENAAR_KEY, RekenBvSubKey.BV_BRUG_PENSIOEN_KEY};

    private void overnemenBedrijfsvoorheffingGewoonOpdracht(
            Opdracht opdracht, LocalDateInterval rekenPeriode, LoonElementManager manager,
            LoonElementManager prevManager) {
        Collection<LoonElement> prevLoonElementen = prevManager.getOpdrachtsElementen(opdracht);

        SortedSetMultimap<MoneyKey, LoonElement> bvSubKeyToLoonElement = TreeMultimap.create(Ordering.arbitrary(), LoonElementComparator.DEFAULT);
        for (LoonElement element : prevLoonElementen) {
            LnedefRegBv regimeBv = element.getRegimeBv();
            MoneyKey bvKey = BvTools.regimeToSubBvKey(regimeBv, rekenPeriode.getEnd());
            bvSubKeyToLoonElement.put(bvKey, element);
        }

        for (RekenBvSubKey bvKey : TE_VERDELEN_BEDRIJFSVOORHEFFING_SUB) {
            RekenBvKey oriBvKey = bvKey.getBasisKey();
            Collection<LoonElement> prevRegimeElementen = bvSubKeyToLoonElement.get(bvKey);
            RekenTools.overnemenVanVorigeBerekening(oriBvKey, manager, prevRegimeElementen);
            RekenBvKey verminderingKey = RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_KEY;
            RekenTools.overnemenVanVorigeBerekening(verminderingKey, manager, prevRegimeElementen);
            RekenBvKey vermindering2Key = RekenBvKey.VERMINDERING_BEDRIJFSVOORHEFFING_WERKBONUS_B_KEY;
            RekenTools.overnemenVanVorigeBerekening(vermindering2Key, manager, prevRegimeElementen);
        }
    }

}
